    class Parser:
        def __init__(self, pattern):
            self.pattern = pattern
            self.pos = 0

        def parse(self):
            return self.parse_alternation()

        def parse_alternation(self):
            left = self.parse_concatenation()
            if self.pos < len(self.pattern) and self.pattern[self.pos] == '|':
                self.pos += 1
                right = self.parse_alternation()
                return ('alt', left, right)
            return left

        def parse_concatenation(self):
            elements = []
            while self.pos < len(self.pattern) and self.pattern[self.pos] not in '|)':
                elements.append(self.parse_quantified())
            return ('concat', elements)

        def parse_quantified(self):
            atom = self.parse_atom()
            if self.pos < len(self.pattern) and self.pattern[self.pos] in '*+?':
                quantifier = self.pattern[self.pos]
                self.pos += 1
                return ('quant', atom, quantifier)
            return atom

        def parse_atom(self):
            if self.pos >= len(self.pattern):
                return ('lit', '')

            ch = self.pattern[self.pos]

            if ch == '.':
                self.pos += 1
                return ('dot',)
            elif ch == '[':
                return self.parse_char_class()
            elif ch == '(':
                self.pos += 1
                result = self.parse_alternation()
                if self.pos < len(self.pattern) and self.pattern[self.pos] == ')':
                    self.pos += 1
                return ('group', result)
            else:
                self.pos += 1
                return ('lit', ch)

        def parse_char_class(self):
            self.pos += 1
            negated = False
            if self.pos < len(self.pattern) and self.pattern[self.pos] == '^':
                negated = True
                self.pos += 1

            ranges = []
